mapper.select:
SELECT s.*
FROM interview_session s
JOIN application_case ac ON ac.id = s.application_case_id
WHERE s.id = #{id}
  AND ac.user_id = #{userId}
  AND ac.deleted_at IS NULL

mapper.update:
UPDATE interview_session
SET total_score = #{totalScore},
    report = #{report},
    ended_at = #{endedAt}
WHERE id = #{id}


UPDATE interview_question
SET model_answer = #{modelAnswer}
WHERE id = #{id}
  AND (model_answer IS NULL OR model_answer = '')

mapper.select:
SELECT MAX(sort_order)
FROM interview_question
WHERE interview_session_id = #{sessionId}
